+/**
+ * Returns the extension of a path.
+ *
+ * @example
+ * ```ts
+ * import { extname } from "path/posix/extname.ts";
+ *
+ * extname("/home/user/file.txt"); // ".txt"
+ * extname("/home/user/file.tar.gz"); // ".gz"
+ * ```
+ */
+export function extname(path: string): string {
+  const last = path.length - 1;
+  let start = -1;
+  let hasDot = false;
+  for (let i = last; i >= 0; i--) {
+    const char = path.charCodeAt(i);
+    if (char === 47) { // "/"
+      if (start !== -1) break;
+      continue;
+    }
+    if (char === 46) { // "."
+      if (start === -1) {
+        start = i;
+        hasDot = true;
+      } else if (i === 0 || path.charCodeAt(i - 1) === 47) {
+        break;
+      }
+    } else if (start !== -1) {
+      break;
+    }
+  }
+  return hasDot && start !== -1 ? path.slice(start) : "";
+}
